  await storage.createQuizQuestion({ moduleId: mod4.id, question: "What is the OSHA Permissible Exposure Limit (PEL) for asbestos?", options: ["0.01 f/cc TWA", "0.05 f/cc TWA", "0.1 f/cc TWA", "1.0 f/cc TWA"], correctIndex: 2, explanation: "The PEL for asbestos is 0.1 fibers per cubic centimeter as an 8-hour time-weighted average. The excursion limit is 1.0 f/cc over 30 minutes.", orderIndex: 0 });
  await storage.createQuizQuestion({ moduleId: mod4.id, question: "An employee is 50 years old with 15 years of asbestos exposure. How often must they receive a chest X-ray?", options: ["Every 5 years", "Every 2 years", "Annually", "Only at pre-placement and termination"], correctIndex: 2, explanation: "For employees over 45 with more than 10 years since first exposure, chest X-rays are required annually under the asbestos standard's frequency schedule.", orderIndex: 1 });
  await storage.createQuizQuestion({ moduleId: mod4.id, question: "Who must interpret chest X-rays taken under the Asbestos Medical Surveillance Standard?", options: ["Any board-certified radiologist", "A NIOSH-certified B-reader", "The employee's personal physician", "Any licensed physician"], correctIndex: 1, explanation: "Chest X-rays taken under the Asbestos Standard must be read by a certified B-reader — a physician who has demonstrated proficiency in ILO Classification of Pneumoconioses through NIOSH certification.", orderIndex: 2 });
  await storage.createQuizQuestion({ moduleId: mod4.id, question: "How long must asbestos medical surveillance records be retained?", options: ["5 years", "Duration of employment", "Duration of employment plus 30 years", "30 years from date of creation"], correctIndex: 2, explanation: "Asbestos medical and exposure records must be retained for the duration of employment plus 30 years, reflecting the long latency period of asbestos-related disease.", orderIndex: 3 });
