  await storage.createQuizQuestion({ moduleId: mod7.id, question: "What constitutes a Standard Threshold Shift (STS) under the Hearing Conservation Standard?", options: ["Any change in hearing at any frequency", "A 10 dB average shift at 2000, 3000, and 4000 Hz in either ear", "A 25 dB shift at any single frequency", "Inability to hear conversational speech"], correctIndex: 1, explanation: "An STS is defined as a change in hearing threshold relative to baseline of an average of 10 dB or more at 2,000, 3,000, and 4,000 Hz in either ear.", orderIndex: 1 });
